INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES ("", 0, 60004, 2, "", 0, 2, "今日の運勢は大吉！　ラッキーカラーは赤！　　　　　　　　　　湧き上がるアイデアの数々に、高笑いが止まりませんわ！", 0, 2, 0, 553);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES ("", 0, 60004, 2, "", 0, 2, "今日の運勢は大吉！　ラッキーワードは「ぴょんぴょん♪」\nおっきな声で一緒に言ってみよ～♪　うさぎさんぴょんぴょ～ん♪", 0, 1, 0, 554);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES ("", 0, 60004, 2, "", 0, 2, "今日の運勢は大吉！　あなたの趣味がもっと広がるかも！\nかんわゆ～～～いショタと～騎士きゅんもゲット～んふふ～♪", 0, 1, 0, 555);
INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES ("", 0, 60004, 2, "", 0, 2, "今日の運勢は大吉！　秘められた力が開花するでしょう！　　　　じゃあ、私の龍眼と力比べしてみようか？　ふふ、冗談だよ～", 0, 1, 0, 556);
